/**
 * shadow-ai-detector.js
 * Phase 3-H: Shadow AI 감지
 *
 * Shadow AI = 팀/회사가 인식하지 못한 AI 도구 사용
 *
 * 감지 방법:
 *   1. 알려지지 않은 소스(source)에서 이벤트 발생
 *   2. 파일 패턴 분석 (GPT/Claude/Copilot 특유 주석/마커 감지)
 *   3. 비정상적인 타임패턴 (한 번에 대량의 파일 수정)
 *   4. 알려진 AI 도구 도메인 접근 패턴
 *   5. 특정 파일 마커 (auto-generated 주석 등)
 */

// ─── 승인된 AI 도구 목록 (조직이 허가한 AI) ──────────
const APPROVED_AI_SOURCES = new Set([
  'claude', 'cursor', 'copilot', 'github-copilot',
  'gemini', 'perplexity', 'openai', 'codeium',
  'slack', 'discord', 'zoom', 'notion',
  'google-calendar', 'calendar', 'local', 'unknown',
]);

// ─── Shadow AI 마커 패턴 ──────────────────────────
const SHADOW_MARKERS = [
  // ChatGPT/GPT-4 특유 패턴
  { pattern: /Certainly! Here'?s (a|the|your)/i,      tool: 'ChatGPT',    confidence: 0.8 },
  { pattern: /As an AI (language model|assistant)/i,  tool: 'ChatGPT',    confidence: 0.9 },
  { pattern: /I apologize, but I (can't|cannot)/i,    tool: 'ChatGPT',    confidence: 0.7 },
  { pattern: /^# Generated by GPT/m,                  tool: 'GPT',        confidence: 1.0 },
  // Copilot 특유 패턴
  { pattern: /# (Copilot|GitHub Copilot) suggestion/i, tool: 'Copilot',   confidence: 0.95 },
  { pattern: /\/\/ Copilot:/i,                         tool: 'Copilot',   confidence: 0.9 },
  // Gemini
  { pattern: /# (Generated|Written) by Gemini/i,      tool: 'Gemini',     confidence: 1.0 },
  { pattern: /Google Gemini/i,                         tool: 'Gemini',     confidence: 0.8 },
  // 일반 AI 생성 마커
  { pattern: /<\/?ai-generated>/i,                    tool: 'Unknown AI', confidence: 0.95 },
  { pattern: /# (DO NOT EDIT|AUTO-GENERATED)/i,       tool: 'AI Generator', confidence: 0.6 },
  { pattern: /this (code|file) was (generated|created) (by|using)/i, tool: 'AI Generator', confidence: 0.7 },
  // Cursor AI
  { pattern: /# cursor:/i,                            tool: 'Cursor',     confidence: 0.9 },
  // 의심스러운 개인 API 키 도메인
  { pattern: /openai\.com\/v1/i,                      tool: 'OpenAI API', confidence: 0.85 },
  { pattern: /api\.anthropic\.com/i,                  tool: 'Claude API', confidence: 0.85 },
  { pattern: /generativelanguage\.googleapis/i,       tool: 'Gemini API', confidence: 0.85 },
];

// ─── 비정상 패턴 임계값 ────────────────────────────
const BULK_EDIT_THRESHOLD  = 20;  // 5분 내 20개 이상 파일 수정
const BULK_EDIT_WINDOW_MS  = 5 * 60 * 1000;
const OFF_HOURS_START      = 0;   // 자정
const OFF_HOURS_END        = 6;   // 새벽 6시 (의심 시간대)

// ─── 메인 감지 함수 ──────────────────────────────
function detectShadowAI(events, approvedSources = APPROVED_AI_SOURCES) {
  const findings = [];

  // ── 1. 미승인 소스 감지 ──────────────────────
  for (const e of events) {
    const src = e.source || e.aiSource || e.data?.toolName || '';
    if (src && !approvedSources.has(src.toLowerCase())) {
      findings.push({
        type:       'unapproved_source',
        severity:   'high',
        source:     src,
        eventId:    e.id,
        timestamp:  e.timestamp,
        message:    `🚫 미승인 AI 도구 감지: "${src}" — 팀 정책에 없는 도구`,
        detail:     { source: src, eventType: e.type },
      });
    }
  }

  // ── 2. 파일 내용 마커 분석 ────────────────────
  for (const e of events) {
    const content = e.data?.content || e.data?.inputPreview || e.data?.contentPreview || '';
    if (!content) continue;

    for (const marker of SHADOW_MARKERS) {
      if (marker.pattern.test(content)) {
        findings.push({
          type:       'ai_content_marker',
          severity:   marker.confidence >= 0.9 ? 'high' : 'medium',
          source:     e.source || 'unknown',
          eventId:    e.id,
          timestamp:  e.timestamp,
          message:    `🔍 AI 생성 콘텐츠 마커 감지: ${marker.tool} (신뢰도 ${Math.round(marker.confidence*100)}%)`,
          detail:     { tool: marker.tool, confidence: marker.confidence, pattern: marker.pattern.source.slice(0, 50) },
        });
        break; // 동일 이벤트에서 첫 번째 매칭만
      }
    }
  }

  // ── 3. 대량 파일 수정 감지 (AI 자동화 의심) ───
  const fileEdits = events.filter(e => ['file.write','file.create'].includes(e.type));
  const sorted    = [...fileEdits].sort((a,b) => new Date(a.timestamp) - new Date(b.timestamp));

  for (let i = 0; i < sorted.length; i++) {
    const t0     = new Date(sorted[i].timestamp).getTime();
    const window = sorted.filter(e => {
      const t = new Date(e.timestamp).getTime();
      return t >= t0 && t <= t0 + BULK_EDIT_WINDOW_MS;
    });

    if (window.length >= BULK_EDIT_THRESHOLD) {
      const sources = [...new Set(window.map(e => e.source || 'unknown'))];
      findings.push({
        type:       'bulk_file_edit',
        severity:   'medium',
        source:     sources.join(', '),
        eventId:    window[0].id,
        timestamp:  window[0].timestamp,
        message:    `⚡ 대량 파일 수정 감지: 5분 내 ${window.length}개 파일 수정 — AI 자동화 의심`,
        detail:     { fileCount: window.length, sources, windowMinutes: 5 },
      });
      i += window.length - 1; // 중복 방지
    }
  }

  // ── 4. 비업무 시간 AI 활동 ────────────────────
  for (const e of events) {
    if (!['tool.end','file.write'].includes(e.type)) continue;
    const hour = new Date(e.timestamp).getHours();
    if (hour >= OFF_HOURS_START && hour < OFF_HOURS_END) {
      findings.push({
        type:       'off_hours_activity',
        severity:   'low',
        source:     e.source || 'unknown',
        eventId:    e.id,
        timestamp:  e.timestamp,
        message:    `🌙 비업무 시간 AI 활동: ${hour}시에 ${e.source || 'AI'} 작업 감지`,
        detail:     { hour, source: e.source },
      });
    }
  }

  // ── 5. API 키 직접 사용 패턴 감지 ─────────────
  for (const e of events) {
    const text = JSON.stringify(e.data || '');
    for (const marker of SHADOW_MARKERS.filter(m => /api|domain/.test(m.pattern.source))) {
      if (marker.pattern.test(text)) {
        findings.push({
          type:       'direct_api_access',
          severity:   'high',
          source:     e.source || 'unknown',
          eventId:    e.id,
          timestamp:  e.timestamp,
          message:    `🔑 AI API 직접 접근 패턴 감지: ${marker.tool} — 승인되지 않은 개인 API 사용 의심`,
          detail:     { tool: marker.tool },
        });
        break;
      }
    }
  }

  // 중복 제거 (같은 타입+소스 조합)
  const seen = new Set();
  return findings.filter(f => {
    const key = `${f.type}:${f.source}:${f.eventId}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  }).sort((a, b) => {
    const order = { high: 0, medium: 1, low: 2 };
    return order[a.severity] - order[b.severity];
  });
}

// ─── 단일 이벤트 실시간 체크 ──────────────────────
function checkEventForShadow(event, approvedSources = APPROVED_AI_SOURCES) {
  return detectShadowAI([event], approvedSources);
}

// ─── 승인 소스 관리 ──────────────────────────────
function getApprovedSources() {
  return [...APPROVED_AI_SOURCES];
}
function addApprovedSource(source) {
  APPROVED_AI_SOURCES.add(source.toLowerCase());
}
function removeApprovedSource(source) {
  APPROVED_AI_SOURCES.delete(source.toLowerCase());
}

module.exports = {
  detectShadowAI,
  checkEventForShadow,
  getApprovedSources,
  addApprovedSource,
  removeApprovedSource,
  APPROVED_AI_SOURCES,
};
